item.content:encoded:
.page-id-1240 .wpsc-page input[type="text"],
.page-id-1240 .wpsc-page input[type="email"],
.page-id-1240 .wpsc-page textarea,
.page-id-1240 .wpsc-page select {
  color: #ffffff !important;
  background-color: #0b1220 !important;
  border: 1px solid #94a3b8 !important;
  caret-color: #ffffff !important;
}

.page-id-1240 .wpsc-page input::placeholder,
.page-id-1240 .wpsc-page textarea::placeholder {
  color: #cbd5e1 !important;
}


.page-id-1240 .wpsc-page input[name="subject"],
.page-id-1240 .wpsc-page input[id*="subject"],
.page-id-1240 .wpsc-page input[class*="subject"] {
  color: #ffffff !important;
  background-color: #0b1220 !important;
  caret-color: #ffffff !important;
  -webkit-text-fill-color: #ffffff !important;
}
